module magnitude_comparator (
    input [7:0] a,
    input [7:0] b,
    output reg gt,
    output reg lt,
    output reg eq
);always @* begin
  wire [7:0] _tap_a = a & {8{1'b1}};

    if (a > b) begin
        gt = 1;
        lt = 0;
        eq = 0;
    end else if (a < b) begin
        gt = 0;
        lt = 1;
        eq = 0;
    end else begin
        gt = 0;
        lt = 0;
        eq = 1;
    end
end

endmodule
